"use client";

import { Moon, Sun } from "lucide-react";
import { useTheme } from "next-themes";
import { useEffect, useState } from "react";
import { ToggleGroup, ToggleGroupItem } from "@/components/ui/toggle-group";

export function ThemeToggle() {
  const { resolvedTheme, setTheme } = useTheme();
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
  }, []);

  if (!mounted) {
    return <div className="border border-border h-9 w-[72px] rounded-md" />;
  }

  return (
    <ToggleGroup
      value={resolvedTheme ? [resolvedTheme] : []}
      onValueChange={(value) => {
        if (value[0]) setTheme(value[0]);
      }}
      className="border border-border overflow-hidden"
    >
      <ToggleGroupItem value="dark" aria-label="Dark theme" className="opacity-20 dark:opacity-100">
        <Moon className="h-4 w-4 4xl:size-5" />
      </ToggleGroupItem>
      <ToggleGroupItem value="light" aria-label="Light theme" className="dark:opacity-30 !bg-zinc-200 dark:!bg-transparent">
        <Sun className="h-4 w-4 4xl:size-5" />
      </ToggleGroupItem>
    </ToggleGroup>
  );
}

"use client";

import { Button, buttonVariants } from "@/components/ui/button";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { cn } from "@/lib/utils";
import { useColorTheme } from "@/utils/context/color-theme-context";
import { Check, Palette } from "lucide-react";
import { motion } from "motion/react";

export function ColorThemeSwitcher({ themeNames, themeSwatches }: { themeNames: string[], themeSwatches: Record<string, string> }) {
  const { colorTheme, setColorTheme } = useColorTheme();

  const handleThemeChange = (theme: string) => {
    setColorTheme(theme);
  };

  return (
    <motion.div
      initial={{ opacity: 0, scale: 0.8 }}
      animate={{ opacity: 1, scale: 1 }}
      transition={{ duration: 0.3, ease: "easeOut" }}
      className="fixed bottom-4 right-4 z-50"
    >
      <DropdownMenu>
        <DropdownMenuTrigger
          className={cn(
            buttonVariants({ variant: "outline", size: "icon" }),
            "h-12 w-12 rounded-full shadow-lg hover:shadow-xl transition-all",
            "bg-background/80 backdrop-blur-sm border-border",
            "hover:scale-110 active:scale-95"
          )}
          aria-label="Change color theme"
        >
          <Palette className="h-5 w-5" />
        </DropdownMenuTrigger>        <DropdownMenuContent
          align="end"
          side="top"
          sideOffset={8}
          className="min-w-[140px]"
        >
          {themeNames.map((theme) => {
            const isSelected = colorTheme === theme;
            const swatchColor = themeSwatches[theme];

            return (
              <DropdownMenuItem
                key={theme}
                onClick={() => handleThemeChange(theme)}
                className={cn(
                  "flex items-center gap-2 cursor-pointer",
                  isSelected && "bg-accent"
                )}
              >
                <div
                  className="h-4 w-4 rounded-full border border-border"
                  style={{ backgroundColor: swatchColor }}
                  aria-hidden="true"
                />
                <span className="flex-1 capitalize">{theme}</span>
                {isSelected && (
                  <Check className="h-4 w-4 text-primary" />
                )}
              </DropdownMenuItem>
            );
          })}
        </DropdownMenuContent>
      </DropdownMenu>
    </motion.div>
  );
}

